/* ----------  STATUTORY RULES NEEDED FOR THIS CASE  ---------- */

/*  Standard deduction (§63(c)(2)(A)) for a joint return (married filing jointly) */
standard_deduction(joint_return, 6000).

/*  Personal-exemption amount (§151(d)(1)) – 2017 is before the 2018-2025 zero-exemption years  */
exemption_amount(2017, 2000).

/*  Income-tax brackets for married individuals filing jointly (§1(a))                */
/*  Bracket  (i) */
tax_bracket_joint(TI, Tax) :-
        TI =< 36900,
        Tax is TI * 0.15.
/*  Bracket  (ii) */
tax_bracket_joint(TI, Tax) :-
        TI > 36900, TI =< 89150,
        Tax is 5535 + 0.28 * (TI - 36900).
/*  Bracket  (iii) */
tax_bracket_joint(TI, Tax) :-
        TI > 89150, TI =< 140000,
        Tax is 20165 + 0.31 * (TI - 89150).
/*  Bracket  (iv) */
tax_bracket_joint(TI, Tax) :-
        TI > 140000, TI =< 250000,
        Tax is 35928.50 + 0.36 * (TI - 140000).
/*  Bracket  (v) */
tax_bracket_joint(TI, Tax) :-
        TI > 250000,
        Tax is 75528.50 + 0.396 * (TI - 250000).


/*  ----------  FACTS FROM THE CASE  ---------- */

income("Alice", 2017, 23191).
income("Bob",   2017, 34081).

/*  Alice and Bob were married on 3-Feb-1992 and file a joint return for 2017  */
file_jointly("Alice", "Bob", 2017).
file_jointly("Bob",   "Alice", 2017).     % convenient symmetric fact


/*  ----------  DERIVED RULES  ---------- */

/*  Sum the incomes of two spouses for a given year */
joint_income(P1, P2, Year, Sum) :-
        income(P1, Year, A1),
        income(P2, Year, A2),
        Sum is A1 + A2.

/*  Number of personal exemptions on a joint return – two spouses, no dependents given */
personal_exemptions_joint(2).

/*  Compute taxable income on a joint return when the couple takes the standard deduction */
taxable_income_joint(P1, P2, Year, TaxableIncome) :-
        joint_income(P1, P2, Year, Gross),
        standard_deduction(joint_return, SD),
        exemption_amount(Year, EA),
        personal_exemptions_joint(NPE),
        ExemptionDeduction is NPE * EA,
        TI0 is Gross - SD - ExemptionDeduction,
        (TI0 < 0 -> TaxableIncome = 0 ; TaxableIncome = TI0).

/*  Final tax computation for a person who filed jointly in a given year               */
/*  Each spouse is jointly and severally liable for the full tax (§1(a), general rule) */
tax(Person, Year, Tax) :-
        file_jointly(Person, Spouse, Year),
        taxable_income_joint(Person, Spouse, Year, TI),
        tax_bracket_joint(TI, Tax).


/*  ----------  QUERY  ---------- */

:- tax("Alice", 2017, Tax), format('Tax result: ~2f~n', [Tax]).
:- halt.
