/* ---------- Computations ---------- */

adjusted_gross_income(Person, Year, AGI) :-
    gross_income(Person, Year, AGI).              /* no above-line mods */

/* Standard deduction allowed unless disallowed under §63(c)(6)(A).
   The problem says Alice takes the standard deduction, so we allow it.  */
allowed_standard_deduction(Person, Year, Ded) :-
    filing_status(Person, Year, Status),
    standard_deduction(Status, Ded).

/* taxable_income = AGI – standard deduction – personal exemptions       */
taxable_income(Person, Year, TI) :-
    adjusted_gross_income(Person, Year, AGI),
    allowed_standard_deduction(Person, Year, SD),
    personal_exemption_amount(PEA),               /* =0 for 2020 */
    TI is max(0, AGI - SD - PEA).

/* Tax from bracket table                                                */
income_tax(Person, Year, Tax) :-
    taxable_income(Person, Year, TI),
    filing_status(Person, Year, Status),
    find_bracket(Status, TI, BaseTax, Rate, Lower),
    Tax is BaseTax + Rate*(TI - Lower).

/* Helper to choose correct bracket                                      */
find_bracket(Status, TI, BaseTax, Rate, Lower) :-
    tax_bracket(Status, Upper, BaseTax, Rate, Lower),
    ( Upper == inf -> true ; TI =< Upper ), !.

/* Public predicate asked in the query                                   */
tax(Person, Year, Tax) :-
    income_tax(Person, Year, Tax).


/* ------------------ Query required by the assignment ----------------- */
:- tax(alice, 2020, Tax), format('Tax result: ~2f~n', [Tax]).
:- halt.
