/* ----------  Statutory rules relevant to the case  ---------- */

/*  §3301 imposes a 6% tax on “wages … with respect to employment”.               */
/*  §3306(b)(1) limits “wages” to the first $7,000 paid to any employee per year. */
/*  §3306(c)(5)(A) excludes from “employment” any                                   */
/*      “service performed by an individual in the employ of his son, daughter,   */
/*       or spouse”.  Consequently, no FUTA tax is due on such services.          */

/* ----------  General predicates implementing those rules  ---------- */

/* relationship(ChildOrParent, Relation, OtherPerson) */
relationship(bob, father, alice).

/* wages(Employer, Employee, Year, Amount) */
wages(alice, bob, 2017, 45252).

/* A service is excluded from FUTA employment under §3306(c)(5)(A)
   if the employee is the parent, child, or spouse of the employer.            */
excluded_employment(Employee, Employer) :-
    relationship(Employee, father, Employer).
excluded_employment(Employee, Employer) :-
    relationship(Employee, mother, Employer).
excluded_employment(Employee, Employer) :-
    relationship(Employee, spouse, Employer).

/* FUTA covers only the first $7,000 of wages per employee per year (§3306(b)(1)). */
covered_wage(AmountPaid, 7000) :- AmountPaid >= 7000, !.
covered_wage(AmountPaid, AmountPaid).

/* Sum all covered wages that are NOT excluded.                                   */
taxable_wages(Employer, Year, Sum) :-
    findall(W,
            ( wages(Employer, Employee, Year, Paid),
              \+ excluded_employment(Employee, Employer),   % not excluded
              covered_wage(Paid, W)
            ),
            List),
    sum_list(List, Sum).

/* FUTA tax: 6 % of taxable wages (§3301).                                         */
tax(Employer, Year, Tax) :-
    taxable_wages(Employer, Year, Taxable),
    Tax is Taxable * 0.06.



/* ----------  Query required by the assignment  ---------- */
:- tax(alice, 2017, Tax), format('Tax result: ~w~n', [Tax]).
:- halt.
